import { execution } from '@dynatrace-sdk/automation-utils';
import { credentialVaultClient } from '@dynatrace-sdk/client-classic-environment-v2';



export default async function ({ execution_id }) {

  const ex = await execution(execution_id);
  const { input } = await fetch(`/platform/automation/v1/executions/${execution_id}`).then((res) => res.json());

  const  dt_client_id_vault = await credentialVaultClient.listCredentials({ name: ""+input.credential_vault_dynatrace_client_id+"", });
  const  clientId_vault_id  = await credentialVaultClient.getCredentialsDetails({ id: dt_client_id_vault.credentials[0].id, });
  const  clientId  = await clientId_vault_id.token;


  const dt_client_secret_vault = await credentialVaultClient.listCredentials({ name: ""+input.credential_vault_dynatrace_client_secret+"", });
  const clientSecret_vault_id  = await credentialVaultClient.getCredentialsDetails({ id: dt_client_secret_vault.credentials[0].id, });
  const clientSecret  = await clientSecret_vault_id.token;



  const accountUuid = input.dynatrace_account_id;


  const scope = "account-idm-read account-idm-write";

  // Get SSO token
  const token = await fetch('https://sso.dynatrace.com/sso/oauth2/token', {
      method: 'POST',
      headers:{
        'Content-Type': 'application/x-www-form-urlencoded'
      },    
      body: new URLSearchParams({
          'grant_type': 'client_credentials',
          'client_id': clientId,
          'client_secret': clientSecret,
          'scope': scope
      })
  }).then(response=>response.json())
    .then(data=>{ return data.access_token; })

  // Uncomment for testing purposes, outputs token in clear text 
  //console.log("Bearer token" + token);




  const deleteUser= await fetch('https://api.dynatrace.com/iam/v1/accounts/' + accountUuid + '/users/' + input.email, {
    method: 'DELETE',
    headers: { 'Content-Type': 'application/json',
          'Authorization': 'Bearer ' + token}
  })            




  return;
}
